/*! \file telnetsrv_ciUE.c
 * \brief Implementation of telnet CI functions for nrUE
 * \author Guido Casati
 * \date 2024
 * \version 0.1
 * \note This file contains telnet-related functions specific to 5G NR UE (nrUE).
 */

#include <sys/types.h>
#include <stdio.h>
#include <unistd.h>
#include <errno.h>
#include <stdlib.h>
#include <string.h>
#include <stdarg.h>
#include <stdint.h>
#include "common/platform_types.h"

#define TELNETSERVERCODE
#include "telnetsrv.h"

/* Forward declarations to avoid pulling in heavy includes */
typedef struct NR_UE_MAC_INST_s NR_UE_MAC_INST_t;
typedef enum {
  UE_NOT_SYNC = 0,
  UE_SYNC,
  UE_SYNC_DONE,
  UE_STATE_MAX
} NR_UE_L2_STATE_t;

/* Extern function declarations */
NR_UE_L2_STATE_t nr_ue_get_sync_state(module_id_t mod_id);
NR_UE_MAC_INST_t *get_mac_inst(module_id_t module_id);
void nr_ue_reset_sync_state(NR_UE_MAC_INST_t *mac);

#define ERROR_MSG_RET(mSG, aRGS...) do { prnt(mSG, ##aRGS); return 1; } while (0)

/* UE L2 state string */
const char* NR_UE_L2_STATE_STR[] = {
  "UE_NOT_SYNC",
  "UE_SYNC",
  "UE_SYNC_DONE"
};

/**
 * Get the synchronization state of a UE.
 *
 * @param buf    User input buffer containing UE ID
 * @param debug  Debug flag (not used)
 * @param prnt   Function to print output
 * @return       0 on success, error code otherwise
 */
int get_sync_state(char *buf, int debug, telnet_printfunc_t prnt)
{
  int ue_id = -1;
  if (!buf) {
    ERROR_MSG_RET("no UE ID provided to telnet command\n");
  } else {
    ue_id = strtol(buf, NULL, 10);
    if (ue_id < 0)
      ERROR_MSG_RET("UE ID needs to be positive\n");
  }
  /* get sync state */
  int sync_state = nr_ue_get_sync_state(ue_id);
  prnt("UE sync state = %s\n", NR_UE_L2_STATE_STR[sync_state]);
  return 0;
}

/**
 * Force a UE into RRC_IDLE state via telnet command.
 * This function validates the UE ID, checks current sync state,
 * and triggers RRC_IDLE transition with F1AP error handling.
 *
 * @param buf    User input buffer containing UE ID
 * @param debug  Debug flag (not used)
 * @param prnt   Function to print output
 * @return       0 on success, error code otherwise
 */
int force_RRC_IDLE(char *buf, int debug, telnet_printfunc_t prnt)
{
  int ue_id = -1;

  if (!buf) {
    ERROR_MSG_RET("No UE ID provided to force_RRC_IDLE command\n");
  } else {
    ue_id = strtol(buf, NULL, 10);
    if (ue_id < 0)
      ERROR_MSG_RET("UE ID needs to be positive\n");
  }

  // Check if UE exists by getting sync state
  NR_UE_L2_STATE_t current_state = nr_ue_get_sync_state(ue_id);
  if (current_state < 0 || current_state >= UE_STATE_MAX) {
    ERROR_MSG_RET("Invalid UE ID: %d - UE does not exist\n", ue_id);
  }

  prnt("UE %d current sync state = %s\n", ue_id, NR_UE_L2_STATE_STR[current_state]);

  // Trigger RRC_IDLE transition with F1AP error handling
  // This resets the MAC state to simulate RRC_IDLE
  NR_UE_MAC_INST_t *mac = get_mac_inst(ue_id);
  if (!mac) {
    ERROR_MSG_RET("Failed to get MAC instance for UE %d\n", ue_id);
  }

  // Reset sync state to simulate RRC_IDLE transition
  nr_ue_reset_sync_state(mac);

  prnt("Successfully forced UE %d to RRC_IDLE state\n", ue_id);
  prnt("UE sync state reset to: %s\n", NR_UE_L2_STATE_STR[UE_NOT_SYNC]);

  return 0;
}

/* Telnet shell command definitions */
static telnetshell_cmddef_t cicmds[] = {
  {"sync_state", "[UE_ID(int,opt)]", get_sync_state},
  {"force_RRC_IDLE", "<UE_ID(int)>", force_RRC_IDLE},
  {"", "", NULL},
};

/* Telnet shell variable definitions (if needed) */
static telnetshell_vardef_t civars[] = {
  {"", 0, 0, NULL}
};

/* Add CI UE commands */
void add_ciUE_cmds(void) {
  add_telnetcmd("ciUE", civars, cicmds);
}"} <|tool_call_end|> <|tool_calls_section_end|>

